EGER', 'column_description': 'Year built', 'value_description': 'Whole number measure or count. Example values: 1997, 2004, 2021.', 'value_examples': '[1997, 2004, 2021]'}, 'last_renovated_year': {'pk': '', 'data_type': 'INTEGER', 'column_description': 'Last renovated year', 'value_description': 'Whole number measure or count. Example values: 2007.', 'value_examples': '[None, 2007, 2025]'}, 'gross_building_area_sqft': {'pk': '', 'data_type': 'INTEGER', 'column_description': 'Gross building area square feet', 'value_description': 'Whole number measure or count. Example values: 1624492, 1346105, 1609089.', 'value_examples': '[1624492, 1346105, 1609089]'}, 'net_leasable_area_sqft': {'pk': '', 'data_type': 'INTEGER', 'column_description': 'Net leasable area square feet', 'value_description': 'Whole number measure or count. Example values: 1295409, 1110494, 1322056.', 'value_examples': '[1295409, 1110494, 1322056]'}, 'land_area_acres': {'pk': '', 'data_type': 'REAL', 'column_description': 'Land area acres', 'value_description': 'Numeric measure that may include decimals. Example values: 70.67, 5.28, 44.56.', 'value_examples': '[70.67, 5.28, 44.56]'}, 'total_units': {'pk': '', 'data_type': 'INTEGER', 'column_description': 'Total units', 'value_description': 'Whole number measure or count.', 'value_examples': '[None, 1119, 222]'}, 'total_parking_bays': {'pk': '', 'data_type': 'INTEGER', 'column_description': 'Total parking bays', 'value_description': 'Whole number measure or count. Example values: 158, 237, 1146.', 'value_examples': '[158, 237, 1146]'}, 'occupancy_stabilized_flag': {'pk': '', 'data_type': 'TEXT', 'column_description': 'Occupancy stabilized flag', 'value_description': 'Binary-style indicator such as Y or N. Example values: Y, Y, Y.', 'value_examples': "['Y', 'N']"}, 'green_certification': {'pk': '', 'data_type': 'TEXT', 'column_description': 'Green certification', 'value_description': 'Categorical or identifier text value. Example values: None, ENERGY STAR, LEED Silver.', 'value_examples': "['None', 'ENERGY STAR', 'LEED Silver']"}, 'energy_rating': {'pk': '', 'data_type': 'TEXT', 'column_description': 'Energy rating', 'value_description': 'Categorical or identifier text value. Example values: B, A+, C.', 'value_examples': "['B', 'A+', 'C']"}, 'capex_plan_flag': {'pk': '', 'data_type': 'TEXT', 'column_description': 'Capex plan flag', 'value_description': 'Binary-style indicator such as Y or N. Example values: Y, Y, N.', 'value_examples': "['Y', 'N']"}, 'capex_budget_cr': {'pk': '', 'data_type': 'REAL', 'column_description': 'Capex budget cr', 'value_description': 'Numeric measure that may include decimals. Example values: 56.15, 108.31, 26.58.', 'value_examples': '[56.15, 108.31, 26.58]'}, 'debt_financed_flag': {'pk': '', 'data_type': 'TEXT', 'column_description': 'Debt financed flag', 'value_description': 'Binary-style indicator such as Y or N. Example values: N, N, N.', 'value_examples': "['N', 'Y']"}, 'loan_account_masked': {'pk': '', 'data_type': 'TEXT', 'column_description': 'Loan account masked', 'value_description': 'Categorical or identifier text value. Example values: XXXX-1106, XXXX-5554, XXXX-7482.', 'value_examples': "['XXXX-1106', 'XXXX-5554', 'XXXX-7482']"}, 'property_manager': {'pk': '', 'data_type': 'TEXT', 'column_description': 'Property manager', 'value_description': 'Categorical or identifier text value. Example values: Cushman PM, CBRE PM, CBRE PM.', 'value_examples': "['Cushman PM', 'CBRE PM', 'JLL PM']"}, 'asset_manager': {'pk': '', 'data_type': 'TEXT', 'column_description': 'Asset manager', 'value_description': 'Categorical or identifier text value. Example values: Summit AM, Northstar AM, Apex AM.', 'value_examples': "['Summit AM', 'Northstar AM', 'Apex AM']"}, 'risk_grade': {'pk': '', 'data_type': 'TEXT', 'column_description': 'Risk grade', 'value_description': 'Categorical or identifier text value. Example values: Medium, Low, Medium.', 'value_examples': "['Medium', 'Low', 'High']"}, 'hold_sel